import os
import pickle
import numpy as np
from PIL import Image
import face_recognition
import cv2
import flask

# Load pre-trained face recognition model
model = pickle.loads(open('face_recognition_model.sav', 'rb').read())

# Path to your employee images directory
employee_images_path = 'employees'

# Initialize an empty set to store known faces' encodings
known_faces_encodings = set()

# Iterate through the employee images and train the model on them
for employee_folder in os.listdir(employee_images_path):
    employee_image_path = os.path.join(employee_images_path, employee_folder)

    # Get all images in employee folder
    for img in os.listdir(employee_image_path):
        img_path = os.path.join(employee_image_path, img)
        image = face_recognition.load_image_file(img_path)
        face_encodings = face_recognition.face_encodings(image)[0]
        known_faces_encodings.add(face_encodings)

# Create Flask web service
app = flask.Flask(__name__)

@app.route('/', methods=['GET'])
def index():
    return "Facial Recognition API"

@app.route('/recognize', methods=['POST'])
def recognize_face():
    # Load the input image from the POST request
    image = flask.request.files['image']
    image = Image.open(image)
    image = np.asarray(image)

    # Find all faces in the given image
    face_locations = face_recognition.face_locations(image, model='cnn')
    face_encodings = face_recognition.face_encodings(image, face_locations)

    # Initialize an empty list for storing results
    results = []

    # Loop through each face in the input image
    for face_encoding, face_location in zip(face_encodings, face_locations):
        # Compare face encodings with known faces
        matches = model.predict([face_encoding])

        # Get the confidence score and predicted name
        match_name = list(known_faces_encodings)[matches[0][1]]
        confidence = matches[0][0]

        # Append the result to the list
        results.append((match_name, confidence))

    # Sort the results by confidence score
    sorted_results = sorted(results, key=lambda x: x[1], reverse=True)

    # Prepare the response
    response = {"names": [result[0] for result in sorted_results],
                "confidences": [result[1] for result in sorted_results]}

    return flask.jsonify(response)

if __name__ == '__main__':
    app.run(port=5000, debug=True)